// Inline the built Patterplay UMD runtime into an ops module, so runExportHtml can produce a SINGLE
// self-contained playable HTML file with no external <script src>. Run after the runtime is built
// (the root build orders @patterkit/runtime before @patterkit/ops). Commit the generated file.
import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const src = resolve(here, "../../runtime/dist/patterplay.min.js");
const out = resolve(here, "../src/playable-runtime.ts");
const js = readFileSync(src, "utf8");
const banner = "// GENERATED by scripts/gen-runtime-blob.mjs from @patterkit/runtime's patterplay.min.js.\n" +
  "// The minified UMD runtime, inlined so runExportHtml can build a single self-contained HTML file.\n" +
  "// Do not edit by hand; re-run `node scripts/gen-runtime-blob.mjs` after a runtime change.\n";
writeFileSync(out, `${banner}export const PLAYABLE_RUNTIME_JS = ${JSON.stringify(js)};\n`);
console.log(`wrote ${out} (${js.length} bytes of runtime)`);
